final:
module top_module (
    input g,
    input f,
    input u,
    input y,
    output reg xxxx
);
    always @(*) begin
        case ({g, f, u, y})
            4'b0100: xxxx = 1'b0;
            4'b0110: xxxx = 1'b1;
            4'b1001: xxxx = 1'b1;
            4'b1010: xxxx = 1'b1;
            4'b0101: xxxx = 1'b1;
            4'b0001: xxxx = 1'b1;
            4'b0000: xxxx = 1'b1;
            4'b0011: xxxx = 1'b1;
            4'b1011: xxxx = 1'b0;
            4'b1000: xxxx = 1'b1;
            4'b1111: xxxx = 1'b1;
            4'b1100: xxxx = 1'b1;
            4'b1110: xxxx = 1'b0;
            4'b0010: xxxx = 1'b0;
            4'b0111: xxxx = 1'b1;
            4'b1101: xxxx = 1'b1;
        endcase
    end
endmodule
